import React, { useEffect, useState, useContext } from 'react';
import api from '../api/axiosConfig';
import { AuthContext } from '../context/AuthContext';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, Hash, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { token } = useContext(AuthContext);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  // --- 1. ROBUST DATA PARSER ---
  const safeParse = (data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      // Handle double-serialized JSON strings from DB
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  };

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_OFFLINE: UNABLE_TO_SYNC_HISTORY");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("CONFIRM_NODE_WIPE: This action cannot be undone.")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) {
      toast.error("WIPE_FAILURE");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("PDF_EXPORT_FAILED");
    }
  };

  useEffect(() => { fetchHistory(); }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT_CHANNELS...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      {/* --- Page Header --- */}
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={22} color="var(--accent-primary)"/> 
          TERMINAL_HISTORY_VAULT
        </h2>
        <div style={vaultBadge}>
          <BarChart3 size={12} /> {history.length} NODES_INDEXED
        </div>
      </div>
      
      {history.length === 0 ? (
        <div style={emptyStyle}>
          <p>NULL_POINTER: NO_STRATEGIES_STORED_IN_VAULT</p>
          <button onClick={() => window.location.href='/generate'} style={initBtn}>GENERATE_FIRST_STRATEGY</button>
        </div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} className="vault-card" style={cardStyle}>
              {/* --- Card Header: Meta Info --- */}
              <div style={cardMeta}>
                <div style={{ display: 'flex', gap: '15px' }}>
                  <span style={dateTag}><Calendar size={11}/> {new Date(item.created_at).toLocaleDateString()}</span>
                  <span style={riskTag}><ShieldCheck size={11}/> RISK_AUDIT: {item.risk_score}/100</span>
                </div>
                <div style={cardActions}>
                  <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View Details"><Eye size={17}/></button>
                  <button onClick={() => handleDownload(item)} style={iconBtn} title="Export PDF"><Download size={17}/></button>
                  <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Wipe Record"><Trash2 size={17}/></button>
                </div>
              </div>

              {/* --- Strategy Goal --- */}
              <h4 style={titleStyle}>{item.goal}</h4>

              {/* --- SEPARATED SECTION: SUMMARY --- */}
              <div style={sectionBlock}>
                <p style={labelSmall}><AlignLeft size={10} /> MARKET_SUMMARY</p>
                <p style={summaryText}>{item.summary}</p>
              </div>

              {/* --- SEPARATED SECTION: HOLDINGS --- */}
              <div style={sectionBlock}>
                <p style={labelSmall}><Hash size={10} /> ASSET_ALLOCATIONS</p>
                <div style={tickerGrid}>
                   {safeParse(item.holdings).map((ticker, i) => (
                     <span key={i} style={tickerBadge}>{ticker}</span>
                   ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* --- PERSISTENT MODAL FOR FULL RATIONALE --- */}
      {selectedItem && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={modalId}>NODE_DATA // SYNC_ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={20}/></button>
            </div>
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              
              <div style={modalSection}>
                <p style={modalLabel}>STRATEGIC_THESIS</p>
                <p style={modalValue}>{selectedItem.summary}</p>
              </div>

              <div style={modalSection}>
                <p style={modalLabel}>AGENTIC_RATIONALE</p>
                <p style={modalValue} className="rationale-scroll">{selectedItem.rationale}</p>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-3px); }
        .rationale-scroll { white-space: pre-wrap; line-height: 1.8; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        .reveal-node { animation: fadeIn 0.4s ease-out; }
      `}</style>
    </div>
  );
};

